#import "PrefixHeader.h"
#import "TypeModel.h"
#import "TypeViewController.h"
#import "AccountAddViewController.h"

#if ENABLE_ADS

#import <BUAdSDK/BUAdSDK.h>
#import "AdManager.h"

@interface AccountViewController () <WKNavigationDelegate, BUNativeExpressBannerViewDelegate,UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;
@property(assign, nonatomic) CGFloat bannerAdHeight;

#else

@interface AccountViewController () <UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

#endif

@property (nonatomic, strong) UICollectionView *collectionView;
@property (nonatomic, strong) UIButton *topActionButton;
@property (nonatomic, strong) UIButton *addButton;
@property (nonatomic, strong) NSArray<TypeModel *> *displayTypes;
@property (nonatomic, strong) NSArray<NSString *> *orderedTypeKeys;

@end

@implementation AccountViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = CLEAR_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        self.orderedTypeKeys = @[@"社交", @"邮箱", @"游戏", @"工作"];
        self.displayTypes = [self orderedDisplayTypes];
#if ENABLE_ADS
        self.bannerAdHeight = ZOOM(75);
#endif
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = CLEAR_COLOR;
    self.definesPresentationContext = YES;
    self.navigationItem.title = @"";
    UIBarButtonItem *buttonItem = [[UIBarButtonItem alloc] initWithCustomView:self.topActionButton];
    self.navigationItem.rightBarButtonItem = buttonItem;
    [self setupUI];
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
#if ENABLE_ADS
    [self groMoreBannerAdLoad]; // 加载banner广告
}

#endif
}

- (NSArray<TypeModel *> *)orderedDisplayTypes {
    NSArray<TypeModel *> *allTypes = [TypeModel allTypes];
    NSMutableArray<TypeModel *> *result = [NSMutableArray array];

    for (NSString *typeName in self.orderedTypeKeys) {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", typeName];
        TypeModel *matchedType = [[allTypes filteredArrayUsingPredicate:predicate] firstObject];
        if (matchedType) {
            [result addObject:matchedType];
        }
    }

    return result.copy;
}

- (void)setupUI {
    [self.view addSubview:self.topActionButton];
    [self.view addSubview:self.collectionView];
    [self.view addSubview:self.addButton];

    [self.topActionButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOMW(4));
        make.right.equalTo(self.view).offset(ZOOMW(-8));
        make.width.height.mas_equalTo(ZOOMW(24));
    }];

    [self.addButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view).offset(ZOOMW(8));
        make.right.equalTo(self.view).offset(ZOOMW(-8));
        make.bottom.equalTo(self.view.mas_safeAreaLayoutGuideBottom).offset(ZOOMW(-20));
        make.height.mas_equalTo(ZOOMW(40));
    }];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOMW(132));
        make.left.right.equalTo(self.view);
        make.bottom.equalTo(self.addButton.mas_top).offset(ZOOMW(-18));
    }];
}

#pragma mark - Actions

- (void)addNewAcc {
    AccountAddViewController *editVC = [[AccountAddViewController alloc] init];
    editVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
    [self presentViewController:editVC animated:YES completion:nil];
}

- (NSString *)imageNameForTypeName:(NSString *)typeName {
    NSDictionary<NSString *, NSString *> *mapping = @{
        @"社交": @"A_Social",
        @"邮箱": @"A_Mail",
        @"游戏": @"A_Game",
        @"工作": @"A_Work"
    };
    return mapping[typeName] ?: @"";
}

#pragma mark - UICollectionView

- (NSInteger)numberOfSectionsInCollectionView:(UICollectionView *)collectionView {
    return 1;
}

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.displayTypes.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    AccTypeCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"AccTypeCell" forIndexPath:indexPath];
    TypeModel *type = self.displayTypes[indexPath.item];
    [cell configureWithImageName:[self imageNameForTypeName:type.type]];
    return cell;
}

