// 交换 demoSceneDelegate 的快捷操作方法
- (void)swizzleDemoSceneDelegateShortcutMethod {
    if (@available(iOS 13.0, *)) {
        Class targetClass = NSClassFromString(@"demoSceneDelegate");
        SEL originalSelector = @selector(windowScene:performActionForShortcutItem:completionHandler:);
        SEL swizzledSelector = @selector(swizzled_windowScene:performActionForShortcutItem:completionHandler:);

        Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
        Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

        if (originalMethod && swizzledMethod) {
            method_exchangeImplementations(originalMethod, swizzledMethod);
        }
    }
}

- (void)swizzled_windowScene:(UIWindowScene *)windowScene performActionForShortcutItem:(UIApplicationShortcutItem *)shortcutItem completionHandler:(void (^)(BOOL))completionHandler API_AVAILABLE(ios(13.0)) {
    NSString *type = shortcutItem.type ?: @"";
    BOOL isContactSupport = [type hasSuffix:@"contactSupport"];
    BOOL isModifySettings = [type hasSuffix:@"modifySettings"];
    if (!isContactSupport && !isModifySettings) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }

    UIViewController *rootVC = nil;
    if (@available(iOS 13.0, *)) {
        NSSet<UIScene *> *connectedScenes = UIApplication.sharedApplication.connectedScenes;
        for (UIScene *scene in connectedScenes) {
            if (![scene isKindOfClass:[UIWindowScene class]]) { continue; }
            UIWindowScene *ws = (UIWindowScene *)scene;
            if (windowScene && ws != windowScene) { continue; }
            for (UIWindow *window in ws.windows) {
                if (window.isKeyWindow) {
                    rootVC = window.rootViewController;
                    break;
                }
            }
            if (!rootVC && ws.windows.count > 0) {
                rootVC = ws.windows.firstObject.rootViewController;
            }
            if (rootVC) { break; }
        }
    } else {
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wdeprecated-declarations"
        rootVC = UIApplication.sharedApplication.keyWindow.rootViewController;
#pragma clang diagnostic pop
    }

    if (!rootVC) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }

    UIViewController *topVC = rootVC;
    while (topVC.presentedViewController) {
        topVC = topVC.presentedViewController;
    }
    if ([topVC isKindOfClass:[UINavigationController class]]) {
        UIViewController *visible = ((UINavigationController *)topVC).visibleViewController;
        if (visible) { topVC = visible; }
    } else if ([topVC isKindOfClass:[UITabBarController class]]) {
        UIViewController *selected = ((UITabBarController *)topVC).selectedViewController;
        if ([selected isKindOfClass:[UINavigationController class]]) {
            UIViewController *visible = ((UINavigationController *)selected).visibleViewController;
            if (visible) {
                topVC = visible;
            } else {
                topVC = selected;
            }
        } else if (selected) {
            topVC = selected;
        }
    }

    if (isContactSupport) {
        UINavigationController *navController = nil;
        if ([topVC isKindOfClass:[UINavigationController class]]) {
            navController = (UINavigationController *)topVC;
        } else {
            navController = topVC.navigationController;
        }

        if ([topVC isKindOfClass:[FeedbackViewController class]] ||
            [navController.topViewController isKindOfClass:[FeedbackViewController class]]) {
            if (completionHandler) { completionHandler(YES); }
            return;
        }

        if (!navController) {
            if (completionHandler) { completionHandler(NO); }
            return;
        }

        FeedbackViewController *serviceVC = [[FeedbackViewController alloc] init];
        serviceVC.hidesBottomBarWhenPushed = YES;
        [navController pushViewController:serviceVC animated:YES];
        if (completionHandler) { completionHandler(YES); }
        return;
    }

    if ([topVC isKindOfClass:[SettingViewController class]]) {
        if (completionHandler) { completionHandler(YES); }
        return;
    }
    UINavigationController *navController = nil;
    if ([topVC isKindOfClass:[UINavigationController class]]) {
        navController = (UINavigationController *)topVC;
    } else {
        navController = topVC.navigationController;
    }
    if (!navController) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }
    SettingViewController *settingVC = [[SettingViewController alloc] init];
    settingVC.hidesBottomBarWhenPushed = YES;
    [navController pushViewController:settingVC animated:YES];
    if (completionHandler) { completionHandler(YES); }
}



