#import "AccountViewController.h"
#import "AccTypeCell.h"
#import "PrefixHeader.h"
#import "TypeModel.h"
#import "TypeViewController.h"
#import "AccountAddViewController.h"

#if ENABLE_ADS

#import <BUAdSDK/BUAdSDK.h>
#import "AdManager.h"

@interface AccountViewController () <WKNavigationDelegate, BUNativeExpressBannerViewDelegate,UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;
@property(assign, nonatomic) CGFloat bannerAdHeight;

#else

@interface AccountViewController () <UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

#endif

@property (nonatomic, strong) UICollectionView *collectionView;
@property (nonatomic, strong) UIButton *topActionButton;
@property (nonatomic, strong) UIButton *addButton;
@property (nonatomic, strong) NSArray<TypeModel *> *displayTypes;
@property (nonatomic, strong) NSArray<NSString *> *orderedTypeKeys;

@end

@implementation AccountViewController

- (UIColor *)primaryBlueColor {
    return RGB(67, 92, 246);
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        self.orderedTypeKeys = @[@"社交", @"邮箱", @"游戏", @"工作"];
        self.displayTypes = [self orderedDisplayTypes];
#if ENABLE_ADS
        self.bannerAdHeight = ZOOM(75);
#endif
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = BACKGROUND_COLOR;
    self.definesPresentationContext = YES;
    self.navigationItem.title = @"Account";
    UIBarButtonItem *buttonItem = [[UIBarButtonItem alloc] initWithCustomView:self.topActionButton];
    self.navigationItem.rightBarButtonItem = buttonItem;
    [self setupUI];
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
#if ENABLE_ADS
    [self groMoreBannerAdLoad]; // 加载banner广告
}

#endif
}

- (NSArray<TypeModel *> *)orderedDisplayTypes {
    NSArray<TypeModel *> *allTypes = [TypeModel allTypes];
    NSMutableArray<TypeModel *> *result = [NSMutableArray array];

    for (NSString *typeName in self.orderedTypeKeys) {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", typeName];
        TypeModel *matchedType = [[allTypes filteredArrayUsingPredicate:predicate] firstObject];
        if (matchedType) {
            [result addObject:matchedType];
        }
    }

    return result.copy;
}

- (void)setupUI {
