#import "AccountModel.h"

@implementation AccountModel

+ (NSMutableArray<AccountModel *> *)allAccs {
    static NSMutableArray *accs = nil;
        static dispatch_once_t onceToken;

        dispatch_once(&onceToken, ^{
            accs = [NSMutableArray array];

            // 尝试从文件加载
            NSArray *savedAccs = [NSArray arrayWithJsonFile:[self filePath] elementClass:[AccountModel class]];
            if (savedAccs) {
                [accs addObjectsFromArray:savedAccs];
            }

//            // 如果没有数据，创建示例数据
//            if (accs.count == 0) {
//                [self createSampleData];
//            }
        });

        return accs;
}

- (instancetype)initWithCoder:(NSCoder *)coder {
    self = [super init];
    if (self) {
        self.accId = [coder decodeIntegerForKey:@"accId"];
        self.type = [coder decodeObjectForKey:@"type"];
        self.name = [coder decodeObjectForKey:@"name"];
        self.account = [coder decodeObjectForKey:@"account"];
        self.password = [coder decodeObjectForKey:@"password"];
        self.note = [coder decodeObjectForKey:@"note"];
        self.createTime = [coder decodeObjectForKey:@"createTime"];
        self.updateTime = [coder decodeObjectForKey:@"updateTime"];
    }
    return self;
}

- (void)encodeWithCoder:(NSCoder *)coder {
    [coder encodeInteger:self.accId forKey:@"accId"];
    [coder encodeObject:self.type forKey:@"type"];
    [coder encodeObject:self.name forKey:@"name"];
    [coder encodeObject:self.account forKey:@"account"];
    [coder encodeObject:self.password forKey:@"password"];
    [coder encodeObject:self.note forKey:@"note"];
    [coder encodeObject:self.createTime forKey:@"createTime"];
    [coder encodeObject:self.updateTime forKey:@"updateTime"];
}

- (NSDictionary *)dictionaryRepresentation {
    NSMutableDictionary *dict = [NSMutableDictionary dictionary];
    dict[@"accId"] = @(self.accId);
    dict[@"type"] = self.type ?: @"";
    dict[@"name"] = self.name ?: @"";
    dict[@"account"] = self.account ?: @"";
    dict[@"password"] = self.password ?: @"";
    dict[@"note"] = self.note ?: @"";
    dict[@"createTime"] = @([self.createTime timeIntervalSince1970]);
    dict[@"updateTime"] = @([self.updateTime timeIntervalSince1970]);
    return dict;
}

+ (void)saveAccs {
    [[AccountModel allAccs] writeToJsonFile:[self filePath]];
}

+ (void)addAcc:(AccountModel *)acc {
    if (!acc.accId) {
        acc.accId = [[NSDate date] timeIntervalSince1970];
    }
    if (!acc.createTime) {
        acc.createTime = [NSDate date];
    }
    acc.updateTime = [NSDate date];

    [[AccountModel allAccs] addObject:acc];

    [self saveAccs];
}

+ (void)updateAcc:(AccountModel *)acc {
    acc.updateTime = [NSDate date];
    [self saveAccs];
}

+ (void)deleteAcc:(NSInteger)accId {
    NSMutableArray *accs = [AccountModel allAccs];
    AccountModel *accToDelete = nil;

    for (AccountModel *acc in accs) {
        if (acc.accId == accId) {
            accToDelete = acc;
            break;
        }
    }

    if (accToDelete) {
        [accs removeObject:accToDelete];
        [self saveAccs];
    }
}

+ (NSArray<AccountModel *> *)searchAccsWithKeyword:(NSString *)keyword {
    if (keyword.length == 0) {
        return [AccountModel allAccs];
    }

    NSPredicate *predicate = [NSPredicate predicateWithFormat:@"title CONTAINS[cd] %@ OR content CONTAINS[cd] %@", keyword, keyword];
    return [[AccountModel allAccs] filteredArrayUsingPredicate:predicate];
}

+ (AccountModel *)accWithId:(NSInteger)accId {
    for (AccountModel *acc in [self allAccs]) {
        if (acc.accId == accId) {
            return acc;
        }
    }
    return nil;
}

#pragma mark - Private
+ (NSString *)filePath {
    return [NSFileManager documentFilePathWithName:@"Accs.json"];
}

@end

