- (void)deleteSelectedAccounts {
    NSArray<AccountModel *> *accounts = [self.displayAccs copy];
    for (AccountModel *account in accounts) {
        if ([self.selectedAccountIDs containsObject:@(account.accId)]) {
            [AccountModel deleteAcc:account.accId];
