@implementation WhiteNoisePlayView

- (instancetype)init {
    self = [super init];
    if (self) {
        [self setUpUI];
        [self setUpEvents];

        if (!self.mode) {
            self.mode = @"A_white.mp3";
        }
        self.targetSeconds = 45;
    }
    return self;
}

- (void)dealloc {
    [self removePlaybackObservers];
    [self.player pause];
    self.player = nil;
}

#pragma mark - ui事件
- (void)play:(UIButton *)button {
    // copyButton显示点击效果
    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    [self removePlaybackObservers];

    NSURL *url = [[NSBundle mainBundle] URLForResource:self.mode withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];

    // 请求权限以在后台播放音频，并允许与其它应用音频混合
    static dispatch_once_t onceToken;
     dispatch_once(&onceToken, ^{   // 只在app启动时设置（执行）一次
       AVAudioSession *audioSession = [AVAudioSession sharedInstance];  // 获取音频会话单例对象
       [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];   // 设置音频会话类别
             /*
                AVAudioSessionCategoryPlayback ：表示 app 将播放音频
                AVAudioSessionCategoryOptionMixWithOthers ：这个选项表示允许与其他音频应用混合播放
                error:nil ：表示忽略任何可能出现的错误（通常应该是捕获并处理可能出现的错误，这里我们选择忽略）
              */
       [audioSession setActive:YES error:nil];  // 激活音频会话（这里同样忽略错误）
     });

    NSInteger selectedMinutes = [self.timeview.time integerValue];
    self.targetSeconds = selectedMinutes > 0 ? selectedMinutes : 45;

    _doneButton.hidden = YES;
    _stopButton.hidden = NO;

    [self.player play];
    //开始计时
    CMTime targetTime = CMTimeMake(self.targetSeconds * 60, 1);
    __weak typeof(self) weakSelf = self;
    self.boundaryTimeObserverToken = [self.player addBoundaryTimeObserverForTimes:@[[NSValue valueWithCMTime:targetTime]]
                                                                             queue:dispatch_get_main_queue()
                                                                        usingBlock:^{
//        [weakSelf stop:nil]; // 触发暂停
//        _doneButton.layer.hidden = NO;
//        _stopButton.layer.hidden = YES;
        [weakSelf stop:_stopButton];
    }];

    self.observedPlayerItem = self.player.currentItem;
    [[NSNotificationCenter defaultCenter] addObserver:self
                                             selector:@selector(runLoopTheMovie:)
                                                 name:AVPlayerItemDidPlayToEndTimeNotification
                                               object:self.observedPlayerItem];
}

- (void)stop:(UIButton *)button {
    // copyButton显示点击效果
    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    _doneButton.layer.hidden = NO;
    _stopButton.layer.hidden = YES;
    [self.player pause];
    //暂停定时器

}

- (void)go:(UIButton *)button {

    [button showClickedAnimationWithLevel:2];
    [self endEditing:YES];

    UIViewController *parentVC = [self findParentViewController];
    WhiteNoiseModePickerViewController *modeVc = [[WhiteNoiseModePickerViewController alloc] init];

    // 设置回调 block
    __weak typeof(self) weakSelf = self; // 避免循环引用
    modeVc.returnBlock = ^(NSString *returnedValue) {
        __strong typeof(weakSelf) strongSelf = weakSelf;

        // 这里处理回传的数据
        NSLog(@"收到回传值: %@", returnedValue);
        strongSelf.mode = returnedValue; // 保存到属性

        // 刷新UI或其他操作
        //            [strongSelf updateUI];

        if ([returnedValue isEqualToString:@"A_white.mp3"]) {
            self.selectedLabel.text = @"White noise";
        } else if ([returnedValue isEqualToString:@"A_pink.mp3"]) {
            self.selectedLabel.text = @"Pink noise";
        }else{
            self.selectedLabel.text = @"Brown noise";
        }
    };

    [parentVC presentViewController:modeVc animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];
}

