- (void)showCustomTimeAlert {
    NSLog(@"tap");
    UIViewController *currentVC = [self findCurrentViewController];
    UIAlertController *alertController = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Enter Time",nil) message:nil preferredStyle:UIAlertControllerStyleAlert];
    [alertController addTextFieldWithConfigurationHandler:^(UITextField * _Nonnull textField) {
        textField.placeholder = NSLocalizedString(@"Enter",nil);
        textField.keyboardType = UIKeyboardTypeNumberPad;
    }];
    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"Cancel",nil) style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) { }];
    UIAlertAction *confirmAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"OK",nil) style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        UITextField *textField = alertController.textFields.firstObject;
        if (textField.text.length > 0) {
            NSString *newTime = textField.text;
            self.targetSeconds = [newTime intValue];
            // 把 botton60 的标题改成用户输入的分钟数
            [self.timeview.botton60 setTitle:newTime forState:UIControlStateNormal];
            [self.timeview.botton60 setTitle:newTime forState:UIControlStateSelected];
            self.timeview.time = newTime;
        } else {
            UIAlertController *warningAlert = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Notice",nil) message:NSLocalizedString(@"No input",nil) preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *okAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"OK",nil) style:UIAlertActionStyleDefault handler:nil];
            [warningAlert addAction:okAction];
            [currentVC presentViewController:warningAlert animated:YES completion:nil];
        }
    }];
    [alertController addAction:cancelAction];
    [alertController addAction:confirmAction];
    [currentVC presentViewController:alertController animated:YES completion:nil];
}

