- (void)setUpEvents {
    [_doneButton addTarget:self action:@selector(play:) forControlEvents:UIControlEventTouchUpInside];
    [_stopButton addTarget:self action:@selector(stop:) forControlEvents:UIControlEventTouchUpInside];
    [_goButton addTarget:self action:@selector(go:) forControlEvents:UIControlEventTouchUpInside];

    __weak typeof(self) weakSelf = self;
    _timeview.onCustomButtonTapped = ^{
        [weakSelf showCustomTimeAlert];
    };
}

- (void)removePlaybackObservers {
    if (self.boundaryTimeObserverToken && self.player) {
        [self.player removeTimeObserver:self.boundaryTimeObserverToken];
        self.boundaryTimeObserverToken = nil;
    }
    if (self.observedPlayerItem) {
        [[NSNotificationCenter defaultCenter] removeObserver:self
                                                        name:AVPlayerItemDidPlayToEndTimeNotification
                                                      object:self.observedPlayerItem];
        self.observedPlayerItem = nil;
    }
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

