#import "ScrollCollectionView.h"
#import "ScrollCollectionCell.h"
#import "PrefixHeader.h"

#define AllCollectionViewCellH ZOOM(98)

@interface ScrollCollectionView () <UICollectionViewDataSource, UICollectionViewDelegate>

@property(strong, nonatomic) UICollectionViewFlowLayout *flowLayout;

@end

static NSString *allCollectionCellReuseId = @"cell";

@implementation ScrollCollectionView
- (instancetype)init {

    self = [super initWithFrame:CGRectZero collectionViewLayout:self.flowLayout];
    if (self) {
        [self setUpUI];

        self.delegate = self;
        self.dataSource = self;
        self.allowsSelection = YES;

        [self registerClass:ScrollCollectionCell.class forCellWithReuseIdentifier:allCollectionCellReuseId];
    }
    return self;
}

#pragma mark - getter
- (NSArray *)cellTitles {
    return @[NSLocalizedString(@"横屏显示", nil),
             NSLocalizedString(@"竖屏显示", nil),
             NSLocalizedString(@"静止弹幕", nil),
             NSLocalizedString(@"滚动弹幕", nil)];
}

#pragma mark - collection view data source

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.cellTitles.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    ScrollCollectionCell *cell = [self dequeueReusableCellWithReuseIdentifier:allCollectionCellReuseId forIndexPath:indexPath];
    cell.mode = self.cellTitles[indexPath.row];
    if (indexPath.row == 0 || indexPath.row == 3) {
        cell.btn.on = YES;
    }
    cell.btn.tag = indexPath.row;
    [cell.btn addTarget:self action:@selector(btnTapped:) forControlEvents:UIControlEventTouchUpInside];
    cell.layer.cornerRadius = ZOOM(12);
    return cell;

}

- (void)btnTapped:(UISwitch *)sender {
    [self updateCellStateForSwitch:sender];
    if ([self.delegate respondsToSelector:@selector(buttonShouldUpdate:)]) {
        [self.delegate buttonShouldUpdate:sender];
    }
}

- (void)updateCellStateForSwitch:(UISwitch *)switchControl {
    NSIndexPath *indexPath = [NSIndexPath indexPathForRow:switchControl.tag inSection:0];
    UICollectionViewCell *cell = [self cellForItemAtIndexPath:indexPath];
    if ([cell isKindOfClass:[ScrollCollectionCell class]]) {
        ScrollCollectionCell *scrollCell = (ScrollCollectionCell *)cell;
        scrollCell.btn.on = switchControl.on;
    }
}

#pragma mark - setUp

- (void)setUpUI {
    self.backgroundColor = [UIColor clearColor];

    self.showsHorizontalScrollIndicator = NO;
    self.showsVerticalScrollIndicator = NO;
    self.alwaysBounceHorizontal = YES;

    [self mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self);
        make.bottom.equalTo(self);
        make.left.equalTo(self);
        make.right.equalTo(self);
    }];
}

#pragma mark - 懒加载

- (UICollectionViewFlowLayout *)flowLayout {
    if (_flowLayout == nil) {

        UICollectionViewFlowLayout *flowLayout = [[UICollectionViewFlowLayout alloc] init];
        flowLayout.scrollDirection = UICollectionViewScrollDirectionVertical;
        flowLayout.minimumInteritemSpacing = ZOOM(11);
        flowLayout.minimumLineSpacing = ZOOM(20);
        flowLayout.itemSize = CGSizeMake(ZOOMW(166), ZOOM(54));
        _flowLayout = flowLayout;
    }
    return _flowLayout;
}
@end

